```cpp
void run(OperationContext* txn,
         const string& dbname,
         const BSONObj& cmdObj,
         BSONObjBuilder& result) {
    const string& user = cmdObj.getStringField("user");
    const string& db = dbname;
    BSONObj cmd = cmdObj.getOwned();

    if (!AuthorizationManager::get(txn)->isAuthorizedForCommand(db, cmd, txn->authInfo())) {
        uasserted(ErrorCodes::Unauthorized, "not authorized for query on admin.system.users");
    }

    status = uassertStatusOK(UserManager::get(txn)->dropUser(user, txn->authInfo()));
    if (!status.isOK()) {
        auditWriteOp(txn, db, false, cmd, status, false);
        uasserted(status.code(), status.reason());
    }

    result.append("ok", 1);
    auditWriteOp(txn, db, true, cmd, status, false);
}
