static int parse_http(char *msg, size_t len)
{
    llhttp_t parser;
    llhttp_settings_t settings;
    char *buf;
    int r;

    memset(&parser, 0, sizeof parser);
    llhttp_settings_init(&settings);
    settings.on_message_begin = on_message_begin;
    settings.on_url = on_url;
    settings.on_header_field = on_header_field;
    settings.on_header_value = on_header_value;
    settings.on_headers_complete = on_headers_complete;
    settings.on_body = on_body;
    settings.on_message_complete = on_message_complete;
    settings.on_chunk_header = on_chunk_header;
    llhttp_init(&parser, HTTP_BOTH, &settings);
    parser.flags |= HTTP_IGNORE_UNKNOWN_FIELDS;
    parser.flags |= HTTP_IGNORE_TRAILING_WS;
    parser.flags |= HTTP_SINGLE_THREADED;
    parser.flags |= HTTP_NO_KEEP_ALIVE;

    buf = msg;
    len = strlen(msg);
    r = llhttp_execute(&parser, buf, len);

    if (r != HTTP_STATUS_COMPLETE)
        return PARSE_ERROR_HEADER;

    if (parser.error != HPE_OK) {
        switch (parser.error) {
            case HPE_HEADER_OVERFLOW:
                return PARSE_ERROR_HEADER;
            case HPE_INVALID_CONTENT_LENGTH:
                return PARSE_ERROR_BODY;
            case HPE_INVALID_CHUNK_SIZE:
                return PARSE_ERROR_BODY;
            default:
                return PARSE_ERROR_BODY;
        }
    }

    return 0;
}
