static ssize_t sg_read(struct sg_fd *sfp, char __user *buf,
                      size_t count, loff_t *f_pos)
{
	int res = 0, knt = 0;
	struct sg_request *srp;
	struct scatterlist *sg;

	if (count > (sfp->device->sg_tablesize * PAGE_SIZE))
		return -EMSGSIZE;

	if (count > (SG_MAX_SEGMENTS * PAGE_SIZE))
		return -EMSGSIZE;

	srp = sg_get_rq(sfp);
	if (!srp)
		return -ENOMEM;

	if (count > sfp->resid)
		count = sfp->resid;

	srp->resid = count;

	srp->in = 1;
	srp->done = 0;
	srp->data = buf;
	srp->resid -= copy_to_user(buf, sfp->resid_ptr, count);
	if (srp->resid) {
		res = -EFAULT;
		goto out;
	}

	srp->done = 1;
	srp->resid = 0;
	srp->in = 0;
	sg = sfp->sglist;
	knt = count;
	while (knt) {
		if (sg->length <= sfp->resid) {
			sfp->resid -= sg->length;
			sg = sg_next(sg);
		} else {
			sg->length -= sfp->resid;
			sg->page_link &= ~SG_CHAIN;
			sg = sg_next(sg);
			sg_set_page(sg, sfp->resid_ptr,
				    sfp->resid, sfp->resid_offset);
			sg->page_link |= SG_CHAIN;
			sg = sg_next(sg);
			sg->length = sfp->resid;
			sg->page_link &= ~SG_CHAIN;
			break;
		}
		knt -= sfp->resid;
		sfp->resid_ptr = sg_page(sg);
		sfp->resid_offset = sg->offset;
		sfp->resid += sg->length;
	}
	srp->resid += sfp->resid;
	sfp->resid_ptr = NULL;
	sfp->resid_offset = 0;

out:
	sg_free_rq(sfp, srp);
	return res ? res : count;
}
