static ErrorCodes::Error decompressMessage(const MessageCompressorId compressorId, const uint8_t* compressedData, size_t compressedSize,
                                          uint8_t* decompressedData, size_t& decompressedSize,
                                          MessageCompressorManager& manager)
{
  if (decompressedSize > MaxMessageSizeBytes)
  {
    manager.LastDecompressionError = ErrorCodes::MessageTooLarge;
    return ErrorCodes::MessageTooLarge;
  }

  if (!manager.MessageCompressors[compressorId].decompress(compressedData, compressedSize, decompressedData, decompressedSize))
  {
    manager.LastDecompressionError = ErrorCodes::DecompressionFailed;
    return ErrorCodes::DecompressionFailed;
  }

  return ErrorCodes::Success;
}

