void uninstallService(const std::wstring &serviceName)
{
    SC_HANDLE manager = OpenSCManager(NULL, NULL, SC_MANAGER_ALL_ACCESS);
    if (manager)
    {
        SC_HANDLE service = OpenService(manager, serviceName.c_str(), SERVICE_ALL_ACCESS);
        if (service)
        {
            if (QueryServiceStatus(service, NULL))
                ControlService(service, SERVICE_CONTROL_STOP, NULL);
            DeleteService(service);
            CloseServiceHandle(service);
        }
        CloseServiceHandle(manager);
    }
    deleteServiceReg(serviceName);
}
